const body = $input.first().json.body || $input.first().json;
const topic_id = body.topic_id;
const project_id = body.project_id;

if (!topic_id) throw new Error("topic_id is required");

return [{ json: { topic_id, project_id } }];

const topic = $('Read Topic').first().json[0];
const promptsArr = $('Read Prompts').first().json;
const project = $('Read Project').first().json[0];

if (!topic) throw new Error('Topic not found');
if (!promptsArr || !promptsArr.length) throw new Error('No prompt_configs found for project');

const promptTypes = ['script_pass1', 'script_pass2', 'script_pass3', 'evaluator', 'visual_director'];
const prompts = {};
for (const pt of promptTypes) {
  const found = promptsArr.find(p => p.prompt_type === pt);
  if (!found) throw new Error(`Missing prompt_config type: ${pt}`);
  prompts[pt] = found.prompt_text;
}

const attempt = (topic.script_attempts || 0) + 1;
const avatar = (topic.avatars && topic.avatars.length) ? topic.avatars[0] : {};

return [{ json: {
  topic,
  avatar,
  project,
  prompts,
  attempt,
  topic_id: topic.id,
  project_id: topic.project_id
} }];

const init = $('Init & Validate Prompts').first().json;
const { topic, avatar, project, prompts } = init;

let prompt = prompts.script_pass1;

const vars = {
  '{{niche_expertise_profile}}': project.niche_expertise_profile || '',
  '{{seo_title}}': topic.seo_title || topic.original_title || '',
  '{{narrative_hook}}': topic.narrative_hook || '',
  '{{avatar_name_age}}': avatar.avatar_name_age || '',
  '{{pain_point}}': avatar.pain_point || '',
  '{{occupation_income}}': avatar.occupation_income || '',
  '{{life_stage}}': avatar.life_stage || '',
  '{{spending_profile}}': avatar.spending_profile || '',
  '{{knowledge_level}}': avatar.knowledge_level || '',
  '{{emotional_driver}}': avatar.emotional_driver || '',
  '{{online_hangouts}}': avatar.online_hangouts || '',
  '{{objection}}': avatar.objection || '',
  '{{dream_outcome}}': avatar.dream_outcome || '',
  '{{playlist_angle}}': topic.playlist_angle || '',
  '{{key_segments}}': topic.key_segments || ''
};

for (const [k, v] of Object.entries(vars)) {
  prompt = prompt.split(k).join(v);
}

return [{ json: { prompt } }];

const response = $input.first().json;
if (response.error || response.type === 'error') {
  return [{ json: {
    isError: true,
    error_message: response.error?.message || JSON.stringify(response.error || response),
    topic_id: $('Init & Validate Prompts').first().json.topic_id,
    project_id: $('Init & Validate Prompts').first().json.project_id
  } }];
}
const text = (response.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
return [{ json: { isError: false, pass1_text: text, topic_id: $('Init & Validate Prompts').first().json.topic_id, project_id: $('Init & Validate Prompts').first().json.project_id } }];

const pass1_text = $json.pass1_text;
const evalPrompt = $('Init & Validate Prompts').first().json.prompts.evaluator;

const prompt = evalPrompt + `\n\n--- SCRIPT TO EVALUATE (Pass 1 Foundation) ---\n${pass1_text}\n\nReturn your evaluation as valid JSON only: { "score": 0.0, "dimensions": { "hook_strength": 0, "persona_integration": 0, "pacing": 0, "specificity": 0, "tts_readability": 0, "visual_prompts": 0, "anti_patterns": 0 }, "feedback": "..." }`;

return [{ json: { eval_prompt: prompt, pass1_text } }];

const evalResponse = $input.first().json;
const pass1_text = $('Build Pass 1 Eval Prompt').first().json.pass1_text;

let score = 6.0;
let dimensions = {};
let feedback = 'Evaluation unavailable';

try {
  const text = (evalResponse.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  const s = cleaned.indexOf('{'), e = cleaned.lastIndexOf('}');
  const parsed = JSON.parse(cleaned.substring(s, e + 1));
  score = parsed.score || 6.0;
  dimensions = parsed.dimensions || {};
  feedback = parsed.feedback || '';
} catch(err) {
  feedback = 'Parse error: ' + err.message;
}

const existingScores = $('Read Topic').first().json[0].script_pass_scores || {};
existingScores.pass1 = {
  score,
  dimensions,
  feedback,
  word_count: pass1_text.split(' ').length,
  timestamp: new Date().toISOString()
};

return [{ json: {
  script_pass_scores: JSON.stringify(existingScores),
  pass1_text,
  pass1_score: score,
  topic_id: $('Init & Validate Prompts').first().json.topic_id,
  project_id: $('Init & Validate Prompts').first().json.project_id
} }];

