const eval_prompt = evalPrompt + `\n\n--- COMBINED SCRIPT (3 passes) ---\n${combined_text.substring(0, 60000)}\n\nReturn your evaluation as valid JSON only: { "score": 0.0, "dimensions": { "hook_strength": 0, "persona_integration": 0, "pacing": 0, "specificity": 0, "tts_readability": 0, "visual_prompts": 0, "anti_patterns": 0 }, "feedback": "..." }`;

return [{ json: {
  combined_text,
  eval_prompt,
  pass1_text,
  pass2_text,
  pass3_text,
  force_passed: false,
  attempt,
  topic_id: $('Init & Validate Prompts').first().json.topic_id,
  project_id: $('Init & Validate Prompts').first().json.project_id
} }];

const evalResponse = $input.first().json;
const combined_data = $('Build Combined Eval').first().json;

let combined_score = 7.0;
let dimensions = {};
let feedback = 'Evaluation unavailable';

try {
  const text = (evalResponse.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  const s = cleaned.indexOf('{'), e = cleaned.lastIndexOf('}');
  const parsed = JSON.parse(cleaned.substring(s, e + 1));
  combined_score = parsed.score || 7.0;
  dimensions = parsed.dimensions || {};
  feedback = parsed.feedback || '';
} catch(err) {
  feedback = 'Parse error: ' + err.message;
}

const force_passed = combined_score < 7.0 && combined_data.attempt >= 3;

const existingScoresStr = $('Merge Pass 3 Scores').first().json.script_pass_scores;
let existingScores = {};
try { existingScores = typeof existingScoresStr === 'string' ? JSON.parse(existingScoresStr) : (existingScoresStr || {}); } catch(e) {}

existingScores.combined = {
  score: combined_score,
  dimensions,
  feedback,
  timestamp: new Date().toISOString()
};

return [{ json: {
  script_pass_scores: JSON.stringify(existingScores),
  combined_score,
  force_passed,
  combined_text: combined_data.combined_text,
  pass1_text: combined_data.pass1_text,
  pass2_text: combined_data.pass2_text,
  pass3_text: combined_data.pass3_text,
  dimensions,
  feedback,
  attempt: combined_data.attempt,
  topic_id: combined_data.topic_id,
  project_id: combined_data.project_id
} }];

const merged = $('Merge Combined Scores').first().json;
const { combined_text, pass1_text, pass2_text, pass3_text } = merged;
const visualPrompt = $('Init & Validate Prompts').first().json.prompts.visual_director;

const sceneRegex = /##?\s*(?:Scene|SCENE)[_\s]?(\d+)[^\n]*/g;
const narrationRegex = /(?:NARRATION|Narration|narration)[:\s]+([^\n]{50,})/g;
const promptRegex = /(?:IMAGE PROMPT|image prompt|IMAGE_PROMPT|VISUAL|visual)[:\s]+([^\n]{20,})/g;

const rawScenes = [];
let sceneNum = 0;
const lines = combined_text.split('\n');
let currentScene = null;
let currentNarration = [];
let currentPrompt = '';
let currentChapter = '';

for (const line of lines) {
  const chapterMatch = line.match(/^#+\s*(Chapter|CHAPTER|Part|PART)\s*[0-9]+[:\s]+(.*)/i);
  if (chapterMatch) { currentChapter = chapterMatch[0].replace(/^#+\s*/, '').trim(); }

  const sceneMatch = line.match(/^##?\s*(?:Scene|SCENE)[_\s]?(\d+)/i);
  if (sceneMatch) {
    if (currentScene) {
      currentScene.narration_text = currentNarration.join(' ').trim();
      currentScene.image_prompt = currentPrompt.trim();
      rawScenes.push(currentScene);
    }
    sceneNum++;
    currentScene = {
      scene_number: sceneNum,
      scene_id: `scene_${String(sceneNum).padStart(3, '0')}`,
      chapter: currentChapter,
      narration_text: '',
      image_prompt: '',
      emotional_beat: ''
    };
    currentNarration = [];
    currentPrompt = '';
  } else if (currentScene) {
    const narLine = line.match(/^(?:NARRATION|narration)[:\s]+(.+)/);
    const imgLine = line.match(/^(?:IMAGE PROMPT|image prompt|VISUAL)[:\s]+(.+)/);
    const emotLine = line.match(/^(?:EMOTIONAL BEAT|emotional beat)[:\s]+(.+)/);
    if (narLine) currentNarration.push(narLine[1]);
    else if (imgLine) currentPrompt = imgLine[1];
    else if (emotLine) currentScene.emotional_beat = emotLine[1];
    else if (line.trim() && !line.startsWith('#') && !line.startsWith('-')) currentNarration.push(line);
  }
}

if (currentScene) {
  currentScene.narration_text = currentNarration.join(' ').trim();
  currentScene.image_prompt = currentPrompt.trim();
  rawScenes.push(currentScene);
}

const finalScenes = rawScenes.length > 0 ? rawScenes : [{
  scene_number: 1, scene_id: 'scene_001', chapter: 'Main', narration_text: combined_text.substring(0, 500), image_prompt: 'Documentary establishing shot', emotional_beat: 'hook'
}];

const sceneList = finalScenes.slice(0, 30).map(s => `${s.scene_id}: ${s.narration_text.substring(0, 100)}`).join('\n');
const visual_prompt = `${visualPrompt}\n\nAssign visual_type (static_image, i2v, or t2v) to each scene below. Return JSON: { "assignments": { "scene_001": "static_image", ... } }\n\nScenes:\n${sceneList}`;

return [{ json: { visual_prompt, raw_scenes_array: finalScenes, topic_id: merged.topic_id, project_id: merged.project_id, combined_score: merged.combined_score, force_passed: merged.force_passed, attempt: merged.attempt } }];

const visualResponse = $input.first().json;
const buildData = $('Build Visual Prompt').first().json;
const rawScenes = buildData.raw_scenes_array;
const topic_id = buildData.topic_id;
const project_id = buildData.project_id;

let assignments = {};
try {
  const text = (visualResponse.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const cleaned = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  const s = cleaned.indexOf('{'), e = cleaned.lastIndexOf('}');
  const parsed = JSON.parse(cleaned.substring(s, e + 1));
  assignments = parsed.assignments || {};
} catch(err) {
  // Default all to static_image if parse fails
}

const VALID_TYPES = ['static_image', 'i2v', 't2v'];

const scenes_array = rawScenes.map(scene => {
  const vt = assignments[scene.scene_id];
  const visual_type = VALID_TYPES.includes(vt) ? vt : 'static_image';
  return {
    topic_id,
    project_id,
    scene_number: scene.scene_number,
    scene_id: scene.scene_id,
    narration_text: scene.narration_text || '',
    image_prompt: scene.image_prompt || '',
    visual_type,
    emotional_beat: scene.emotional_beat || '',
    chapter: scene.chapter || '',
    audio_status: 'pending',
    image_status: 'pending',
    video_status: 'pending',
    clip_status: 'pending',
    skipped: false
  };
});

const word_count = rawScenes.reduce((sum, s) => sum + s.narration_text.split(' ').length, 0);
const scene_count = scenes_array.length;

const script_json = JSON.stringify(scenes_array);
const script_metadata = JSON.stringify({
  video_metadata: {
    title: $('Init & Validate Prompts').first().json.topic.seo_title || $('Init & Validate Prompts').first().json.topic.original_title,
    description: `A detailed documentary about ${$('Init & Validate Prompts').first().json.topic.narrative_hook || ''}`,
    tags: ['documentary', $('Init & Validate Prompts').first().json.project.niche || ''],
    thumbnail_prompt: scenes_array[0]?.image_prompt || ''
  },
  generation_stats: {
    word_count,
    scene_count,
    visual_type_breakdown: {
      static_image: scenes_array.filter(s => s.visual_type === 'static_image').length,
      i2v: scenes_array.filter(s => s.visual_type === 'i2v').length,
      t2v: scenes_array.filter(s => s.visual_type === 't2v').length
    },
    quality_score: buildData.combined_score,
    force_passed: buildData.force_passed,
    attempt: buildData.attempt
  }
});

return [{ json: { scenes_array, script_json, script_metadata, word_count, scene_count, topic_id, project_id, combined_score: buildData.combined_score, force_passed: buildData.force_passed, attempt: buildData.attempt } }];

const errData = $input.first().json;
const topic_id = errData.topic_id || $('Init & Validate Prompts').first().json?.topic_id;
const project_id = errData.project_id || $('Init & Validate Prompts').first().json?.project_id;
const error_message = errData.error_message || 'Unknown error in script generation';

return [{ json: { topic_id, project_id, error_message } }];
